evaluatorContext.idealResponse:
Design a graceful degradation strategy for the recommendation service:

SERVICE: Product Recommendations
SLA: 99.9% availability, <200ms p95 latency

---

SERVICE LEVELS:

LEVEL 1: FULL AI (Optimal)
```json
{
  "level": 1,
  "name": "full_ai",
  "description": "Full AI personalization with real-time inference",
  "capabilities": {
    "personalization": "real-time user embedding",
    "model": "latest production model",
    "features": ["browsing history", "purchase history", "similar users", "trending boost"],
    "expected_ctr_lift": "25%"
  },
  "requirements": {
    "ai_service": "healthy",
    "latency_p95": "<150ms",
    "error_rate": "<1%"
  }
}
```

LEVEL 2: CACHED AI (Degraded)
```json
{
  "level": 2,
  "name": "cached_ai",
  "description": "AI using cached user embeddings (6-hour staleness)",
  "capabilities": {
    "personalization": "cached user embedding",
    "model": "latest production model",
    "features": ["cached preferences", "similar users", "trending boost"],
    "expected_ctr_lift": "15%"
  },
  "trade_offs": [
    "Recommendations may not reflect recent browsing",
    "New users get generic recommendations"
  ]
}
```

LEVEL 3: RULE-BASED (No AI)
```json
{
  "level": 3,
  "name": "rule_based",
  "description": "Pre-computed rules, no AI inference",
  "capabilities": {
    "personalization": "category affinity only",
    "model": "none",
    "features": ["category match", "price range match", "brand affinity"],
    "expected_ctr_lift": "5%"
  },
  "implementation": {
    "rules": [
      "Show items from user's most-viewed category",
      "Match price range to user's purchase history",
      "Boost brands user has purchased before"
    ]
  }
}
```

LEVEL 4: STATIC (Emergency)
```json
{
  "level": 4,
  "name": "static",
  "description": "Pre-computed popular items only",
  "capabilities": {
    "personalization": "none",
    "model": "none",
    "features": ["global trending", "best sellers"],
    "expected_ctr_lift": "0%"
  },
  "implementation": {
    "source": "hourly-refreshed popularity cache",
    "fallback": "last known popular items"
  }
}
```

---

DEGRADATION TRIGGERS:

```json
{
  "triggers": {
    "level_1_to_2": {
      "conditions": [
        {"metric": "ai_latency_p95", "threshold": ">150ms", "duration": "2min"},
        {"metric": "ai_error_rate", "threshold": ">5%", "duration": "1min"}
      ],
      "operator": "OR"
    },
    "level_2_to_3": {
      "conditions": [
        {"metric": "ai_service_health", "threshold": "unhealthy", "duration": "30s"},
        {"metric": "ai_latency_p95", "threshold": ">500ms", "duration": "1min"},
        {"metric": "ai_error_rate", "threshold": ">20%", "duration": "1min"}
      ],
      "operator": "OR"
    },
    "level_3_to_4": {
      "conditions": [
        {"metric": "rule_engine_health", "threshold": "unhealthy"},
        {"metric": "database_latency", "threshold": ">200ms", "duration": "1min"}
      ],
      "operator": "OR"
    }
  }
}
```

---

RECOVERY CRITERIA:

```json
{
  "recovery": {
    "level_4_to_3": {
      "conditions": [
        {"metric": "database_latency", "threshold": "<100ms", "duration": "2min"},
        {"metric": "rule_engine_health", "threshold": "healthy", "duration": "2min"}
      ],
      "operator": "AND",
      "cooldown": "5min"
    },
    "level_3_to_2": {
      "conditions": [
        {"metric": "ai_service_health", "threshold": "healthy", "duration": "5min"},
        {"metric": "ai_error_rate", "threshold": "<5%", "duration": "5min"}
      ],
      "operator": "AND",
      "cooldown": "10min"
    },
    "level_2_to_1": {
      "conditions": [
        {"metric": "ai_latency_p95", "threshold": "<100ms", "duration": "10min"},
        {"metric": "ai_error_rate", "threshold": "<1%", "duration": "10min"},
        {"metric": "cache_freshness", "threshold": "<1hour"}
      ],
      "operator": "AND",
      "cooldown": "15min"
    }
  },
  "recovery_strategy": "gradual",
  "traffic_ramp": [10, 25, 50, 75, 100]
}
```

---

OBSERVABILITY:

```json
{
  "metrics": [
    {
      "name": "ai_latency_p95",
      "type": "histogram",
      "unit": "ms",
      "alert_thresholds": {"warning": 100, "critical": 200}
    },
    {
      "name": "ai_error_rate",
      "type": "gauge",
      "unit": "percent",
      "alert_thresholds": {"warning": 2, "critical": 10}
    },
    {
      "name": "current_service_level",
      "type": "gauge",
      "values": [1, 2, 3, 4],
      "alert_on_change": true
    },
    {
      "name": "degradation_events",
      "type": "counter",
      "labels": ["from_level", "to_level", "trigger_reason"]
    },
    {
      "name": "recommendation_quality",
      "type": "gauge",
      "unit": "ctr_percent",
      "baseline_by_level": {"1": 8.5, "2": 7.0, "3": 5.5, "4": 4.0}
    }
  ],
  "alerts": [
    {
      "name": "ServiceDegraded",
      "condition": "current_service_level > 1",
      "severity": "warning",
      "notify": ["slack-oncall"]
    },
    {
      "name": "ServiceCritical",
      "condition": "current_service_level >= 3",
      "severity": "critical",
      "notify": ["pagerduty"]
    }
  ],
  "dashboard": "grafana/recommendations-health"
}
```
